"""
This is the main module to launch the program
"""

from board import Board
from player import Player
import os

def run():
    print("Welcome to Checkers!")
    board = Board()
    player1 = Player('White')
    player2 = Player('Black')

    current_player = player1 if board.turn == 'W' else player2

    while True:
        board.display()
        move_input = input(f"{current_player.name}, enter your move (e.g., E2-E4): ").strip().upper()

        try:
            from_pos, to_pos = map(lambda x: x.strip(), move_input.split('-'))
            move = Move(from_pos, to_pos)
            board.make_move(move, current_player)
            current_player = player1 if current_player == player2 else player2
        except ValueError as e:
            print(f"Invalid move: {e}")
            continue

        if board.check_winner():
            winner = 'White' if board.turn == 'B' else 'Black'
            board.display()
            print(f"{winner} wins!")
            break

if __name__ == "__main__":
    run()
```

### Board.py

```python
"""
Represents the game board and its state.
"""

class Board:
    def __init__(self):
        self.board = [[None] * 8 for _ in range(8)]
        self.turn = 'W'
        self.initialize_board()

    def initialize_board(self):
        # Initialize pieces on the board
        for row in range(3):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece('Black')
        for row in range(5, 8):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece('White')

    def display(self):
        print("   A B C D E F G H")
        for i, row in enumerate(self.board):
            print(f"{i+1} ", end="")
            for piece in row:
                if piece is None:
                    print(". ", end="")
                else:
                    print(f"{piece.symbol()} ", end="")
            print()

    def make_move(self, move, player):
        from_pos = (int(move.from_pos[1]) - 1, ord(move.from_pos[0]) - 97)
        to_pos = (int(move.to_pos[1]) - 1, ord(move.to_pos[0]) - 97)

        piece = self.board[from_pos[0]][from_pos[1]]
        if piece is None or piece.color != player.color:
            raise ValueError("Invalid move: Piece does not belong to the current player")

        self.board[from_pos[0]][from_pos[1]] = None
        self.board[to_pos[0]][to_pos[1]] = piece

    def check_winner(self):
        # Check if there are no pieces left of one color
        black_count = sum(row.count('B') for row in self.board)
        white_count = sum(row.count('W') for row in self.board)
        return black_count == 0 or white_count == 0

class Piece:
    def __init__(self, color):
        self.color = color

    def symbol(self):
        if self.color == 'Black':
            return 'B'
        elif self.color == 'White':
            return 'W'
```

